        expect(updateMap.get('name')).toBe('my-vpc');
        expect(updateMap.get('customFlag')).toBe('true');
    });
});

import gremlin from 'gremlin';

const t = gremlin.process.t;

// These field-name literals ARE the wire contract between scanners and
// Neptune. Keeping them inline here (rather than importing DatabaseFields
// from the .ts constants file) means the helpers are a pure-ESM module
// that can be unit-tested without a TS loader. If a field name ever
// changes in database-fields.constants.ts, it has to change here too —
// the unit tests in __tests__/database/neptune-maps.test.js assert on
// these exact field names.
const FIELDS = Object.freeze({
    ACCOUNTID: 'accountID',
    CLOUD: 'cloud',
    CUSTOMER: 'customer',
    INSERTED: 'inserted',
    INSERTED_LONG: 'insertedLong',
    REGION: 'region',
    RESOURCETYPE: 'resourceType',
    SOTERIA_STATUS: 'soteriaStatus',
    UPDATED: 'updated',
    UPDATED_LONG: 'updatedLong',
});
const STATUS_ACTIVE = 'active';

const safeValue = (value) => (value === undefined || value === null) ? '' : value;

/**
 * Pure helper that populates the create/update maps saveToNeptune hands to
 *   mergeV(lookupMap)
 *     .option(onCreate, createMap)
 *     .option(onMatch, updateMap, single)
 *
 * Invariants (covered by unit tests in __tests__/database/neptune-maps.test.js):
 *  - INSERTED / INSERTED_LONG live in createMap only — never rewritten on
 *    subsequent saves for an existing vertex.
 *  - UPDATED / UPDATED_LONG live in both maps and are refreshed on every call.
 *  - CUSTOMER / CLOUD live in both maps so long-lived vertices that only
 *    ever take the match path still get these refreshed.
 *  - REGION / ACCOUNTID / RESOURCETYPE respect caller-supplied values on
 *    both paths — default from event only when the caller didn't set them.
 *  - SOTERIA_STATUS is always refreshed to 'active'.
 */
export function buildSaveToNeptuneMaps(event, createMap, updateMap, now = Date.now(), dt = new Date(now).toISOString()) {
    // Sanitise nulls/undefined to '' in caller-supplied values.
    for (const [key, value] of createMap.entries()) {
        createMap.set(key, safeValue(value));
    }
    for (const [key, value] of updateMap.entries()) {
        updateMap.set(key, safeValue(value));
    }

    // createMap — respect caller-supplied region / accountID / resourceType.
    if (!createMap.has(FIELDS.REGION)) {
        createMap.set(FIELDS.REGION, safeValue(event['region']));
    }
    if (!createMap.has(FIELDS.ACCOUNTID)) {
        createMap.set(FIELDS.ACCOUNTID, safeValue(event[FIELDS.ACCOUNTID]));
    }
    createMap.set(FIELDS.CUSTOMER, safeValue(event['customer']));
    createMap.set(FIELDS.CLOUD, safeValue(event['cloud']));
    if (!createMap.has(FIELDS.RESOURCETYPE)) {
        createMap.set(FIELDS.RESOURCETYPE, safeValue(event[FIELDS.RESOURCETYPE]));
    }

    createMap.set(FIELDS.INSERTED, dt);
    createMap.set(FIELDS.INSERTED_LONG, now);
    createMap.set(FIELDS.UPDATED, dt);
    createMap.set(FIELDS.UPDATED_LONG, now);
    createMap.set(FIELDS.SOTERIA_STATUS, STATUS_ACTIVE);

    // updateMap — same invariants minus the INSERTED* fields.
    if (!updateMap.has(FIELDS.REGION)) {
        updateMap.set(FIELDS.REGION, safeValue(event['region']));
    }
    if (!updateMap.has(FIELDS.ACCOUNTID)) {
        updateMap.set(FIELDS.ACCOUNTID, safeValue(event[FIELDS.ACCOUNTID]));
    }
    if (!updateMap.has(FIELDS.RESOURCETYPE)) {
        updateMap.set(FIELDS.RESOURCETYPE, safeValue(event[FIELDS.RESOURCETYPE]));
    }
    updateMap.set(FIELDS.CUSTOMER, safeValue(event['customer']));
    updateMap.set(FIELDS.CLOUD, safeValue(event['cloud']));
    updateMap.set(FIELDS.UPDATED, dt);
    updateMap.set(FIELDS.UPDATED_LONG, now);
    updateMap.set(FIELDS.SOTERIA_STATUS, STATUS_ACTIVE);

    return { createMap, updateMap };
}

/**
 * Pure helper that builds the create/update maps emptyCreate passes to
 *   mergeV(lookupMap)
 *     .option(onCreate, createMap)
 *     .option(onMatch, updateMap, single)
 *
 * Invariants:
 *  - t.label only in createMap (Neptune cannot relabel existing vertices).
 *  - INSERTED / INSERTED_LONG only in createMap.
 *  - UPDATED / UPDATED_LONG in both, refreshed on every call.
 *  - CUSTOMER / CLOUD in both so long-lived cross-referenced vertices
 *    don't drift.
 *  - targetProperties supplied by the caller flow into both maps and
 *    override the defaults from event.
 */
export function buildEmptyCreateMaps(event, targetLabel, targetProperties, resourceType, now = Date.now(), dt = new Date(now).toISOString()) {
    const createMap = new Map();
    createMap.set(t.label, targetLabel);
    createMap.set(FIELDS.REGION, event['region']);
    createMap.set(FIELDS.CUSTOMER, event['customer']);
    createMap.set(FIELDS.ACCOUNTID, event['accountID']);
    createMap.set(FIELDS.CLOUD, event['cloud']);
    createMap.set(FIELDS.RESOURCETYPE, resourceType);
    createMap.set(FIELDS.INSERTED, dt);
    createMap.set(FIELDS.INSERTED_LONG, now);
    createMap.set(FIELDS.UPDATED, dt);
    createMap.set(FIELDS.UPDATED_LONG, now);
    // Caller-supplied properties override the defaults.
    for (const [key, value] of targetProperties.entries()) {
        createMap.set(key, value);
    }

    const updateMap = new Map();
    updateMap.set(FIELDS.UPDATED, dt);
    updateMap.set(FIELDS.UPDATED_LONG, now);
    updateMap.set(FIELDS.CUSTOMER, event['customer']);
    updateMap.set(FIELDS.CLOUD, event['cloud']);
    for (const [key, value] of targetProperties.entries()) {
        updateMap.set(key, value);
    }

    return { createMap, updateMap };
}

